import{_ as a,o as r,c as e,b as t}from"./app-13b67eb6.js";const n="/noniBlog/assets/browser-79c07cd7.png",i={},o=t('<h1 id="浏览器" tabindex="-1"><a class="header-anchor" href="#浏览器" aria-hidden="true">#</a> 浏览器</h1><h2 id="输入url后发生了什么" tabindex="-1"><a class="header-anchor" href="#输入url后发生了什么" aria-hidden="true">#</a> 输入URL后发生了什么</h2><p>解析url；通过DNS查询找到IP地址；进行TCP连接建立请求并发送；得到响应数据后进行渲染。</p><h2 id="渲染过程-关键渲染路径" tabindex="-1"><a class="header-anchor" href="#渲染过程-关键渲染路径" aria-hidden="true">#</a> 渲染过程（关键渲染路径）</h2><p>HTML 解析-&gt;DOM树</p><p>CSS 解析 -&gt; CSSOM树（CSS对象模型）</p><p>根据DOM树和CSSOM树构建渲染树</p><p>进行<strong>布局计算</strong>，根据计算结果进行<strong>绘制</strong></p><p>包含多个层的页面会进行<strong>合成</strong></p><blockquote><p>绘制 https://juejin.cn/post/6938009725745233934#heading-7</p></blockquote><h2 id="浏览器进程" tabindex="-1"><a class="header-anchor" href="#浏览器进程" aria-hidden="true">#</a> 浏览器进程</h2><p>渲染进程（GUI线程在这里）</p><p>网络进程</p><p>浏览器主进程</p><p>GPU进程</p><p>插件进程</p><p><img src="'+n+'" alt="图片"></p><h3 id="gpu进程跟gui线程的区别" tabindex="-1"><a class="header-anchor" href="#gpu进程跟gui线程的区别" aria-hidden="true">#</a> GPU进程跟GUI线程的区别</h3><p>GUI线程：在渲染进程里，每个标签页一个，负责执行js代码，解析DOM，样式计算，布局，绘制指令生成</p><p>GPU进程：全局只有一个，绘制UI界面，负责合成图层、硬件加速、把内容渲染到屏幕上</p><h3 id="重排-重绘-合成" tabindex="-1"><a class="header-anchor" href="#重排-重绘-合成" aria-hidden="true">#</a> 重排 重绘 合成</h3><ul><li>重排<strong>会改变元素的几何位置</strong>，需要更新完整的渲染流水线，所以开销也是最大的</li><li>重绘只是<strong>修改元素的颜色等非位置属性</strong>，所以省去了布局和分层阶段，开销比重排小</li><li>合成只会<strong>由已提升会合成层的transform或opacity触发，只涉及几何变换或透明度变换</strong>，会跳过前面的流程，直接进入合成阶段，开销最小。（<strong>transform或opacity若未提升为合成层，则依然会触发paint</strong>）</li></ul>',22),s=[o];function h(p,d){return r(),e("div",null,s)}const l=a(i,[["render",h],["__file","liulanqihewangluo.html.vue"]]);export{l as default};
